const settings = $('Load Global Settings').first()?.json ?? {};
const request = $('Send Case Tracking Email Webhook').first()?.json ?? $input.first()?.json ?? {};
const body = request.body ?? request.query ?? request;
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const truthy = (value) => ['1', 'true', 'yes', 'y', 'on'].includes(clean(value).toLowerCase());
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = authority + ':' + forwardedPort;
  }
  return proto + '://' + authority;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const caseId = /^[0-9a-fA-F-]{36}$/.test(clean(body.case_id)) ? clean(body.case_id) : '';
const returnUrl = clean(body.return_url) || (n8nBaseUrl + '/webhook/case-tracking?view=dashboard');
const deliveryMode = truthy(body.test_mode) ? 'test' : 'production';
const errorMessage = !caseId ? 'case_id is required.' : (!clean(body.template_key) ? 'template_key is required.' : (!clean(body.to) ? 'A recipient is required.' : (!clean(body.rendered_subject) ? 'Subject is required.' : (!String(body.rendered_message ?? '').trim() ? 'Message is required.' : ''))));
return [{ json: { case_id: caseId, template_key: clean(body.template_key), signature_template_key: clean(body.signature_template_key), to: clean(body.to), return_url: returnUrl, n8n_base_url: n8nBaseUrl, delivery_mode: deliveryMode, test_recipient: clean(settings.email_test_recipient) || 'steve.short@gmail.com', sender_name: clean(settings.email_sender_name) || 'Steve Short', reply_to: clean(settings.email_reply_to) || 'members.avondaleltc@gmail.com', rendered_subject: clean(body.rendered_subject), rendered_message: body.rendered_message ?? '', rendered_signature: body.rendered_signature ?? '', email_type: clean(body.email_type) === 'html' ? 'html' : 'text', error_message: errorMessage } }];

const requestInput = $('Resolve Send Request').first()?.json ?? {};
const contextRow = $('Load Send Context').first()?.json ?? {};
const message = contextRow.error_message || requestInput.error_message || 'Unable to send the email.';
const redirectTo = (requestInput.return_url || '#') + (((requestInput.return_url || '#').includes('?')) ? '&' : '?') + 'error=' + encodeURIComponent(message);
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = '<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=' + escapeHtml(redirectTo) + '"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Email not sent</title></head><body><p>' + escapeHtml(message) + '</p><p><a href="' + escapeHtml(redirectTo) + '">Back to case</a></p></body></html>';
return [{ json: { html } }];

const input = $('Resolve Send Request').first()?.json ?? {};
const sqlLiteral = (value) => "'" + String(value ?? '').replace(/'/g, "''") + "'";
const sql = [
  'WITH selected_case AS (',
  '  SELECT * FROM public.cases WHERE id = ' + sqlLiteral(input.case_id) + '::uuid',
  ')',
  'SELECT',
  "  COALESCE((SELECT to_jsonb(selected_case) FROM selected_case), '{}'::jsonb) AS case_row,",
  "  CASE WHEN NOT EXISTS (SELECT 1 FROM selected_case) THEN 'Case not found.' ELSE NULL END AS error_message"
].join('\n');
return [{ json: { ...input, sql } }];

const input = $('Resolve Send Request').first()?.json ?? {};
const result = $('Load Send Context').first()?.json ?? {};
const parseMaybe = (value, fallback) => {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'string') { try { return JSON.parse(value); } catch { return fallback; } }
  return value;
};
const caseRow = parseMaybe(result.case_row, {}) || {};
const intendedRecipient = input.to;
const actualRecipient = input.delivery_mode === 'production' ? intendedRecipient : input.test_recipient;
const combinedMessage = input.email_type === 'html' ? String(input.rendered_message || '') + String(input.rendered_signature || '') : [String(input.rendered_message || '').trim(), String(input.rendered_signature || '').trim()].filter(Boolean).join('\n\n');
return [{ json: { case_id: input.case_id, case_title: caseRow.title || '', template_key: input.template_key, signature_template_key: input.signature_template_key, return_url: input.return_url, n8n_base_url: input.n8n_base_url, delivery_mode: input.delivery_mode, intended_recipient: intendedRecipient, actual_recipient: actualRecipient, sender_name: input.sender_name, reply_to: input.reply_to, rendered_subject: input.rendered_subject, rendered_message: input.rendered_message, rendered_signature: input.rendered_signature, email_type: input.email_type, combined_message: combinedMessage } }];

const payload = $('Build Send Payload').first()?.json ?? {};
const gmail = $('Send Gmail Message').first()?.json ?? {};
const sqlLiteral = (value) => value === null || value === undefined ? 'NULL' : "'" + String(value).replace(/'/g, "''") + "'";
const messageId = gmail.id || gmail.message?.id || '';
const threadId = gmail.threadId || gmail.message?.threadId || '';
const recipients = JSON.stringify({ to: payload.intended_recipient, actual_to: payload.actual_recipient, delivery_mode: payload.delivery_mode });
const bodyHtmlSql = payload.email_type === 'html' ? sqlLiteral(payload.combined_message) : 'NULL';
const bodyTextSql = payload.email_type === 'html' ? 'NULL' : sqlLiteral(payload.combined_message);
const sql = [
  'WITH logged_email AS (',
  '  INSERT INTO public.case_emails (case_id, direction, subject, body_html, body_text, recipients, template_key, signature_template_key, delivery_mode, gmail_message_id, gmail_thread_id, created_by, sent_at)',
  '  VALUES (' + [sqlLiteral(payload.case_id) + '::uuid', sqlLiteral('outgoing'), sqlLiteral(payload.rendered_subject), bodyHtmlSql, bodyTextSql, sqlLiteral(recipients) + '::jsonb', sqlLiteral(payload.template_key), sqlLiteral(payload.signature_template_key), sqlLiteral(payload.delivery_mode), sqlLiteral(messageId), sqlLiteral(threadId), sqlLiteral('case-tracking'), 'now()'].join(', ') + ')',
  '  RETURNING case_id',
  '), updated_case AS (',
  '  UPDATE public.cases',
  "  SET status = 'Waiting', updated_at = now(), last_outbound_at = now()",
  '  WHERE id = (SELECT case_id FROM logged_email)',
  '  RETURNING id',
  ')',
  'SELECT id::text AS case_id FROM updated_case'
].join('\n');
return [{ json: { ...payload, sql } }];

const item = $('Build Log SQL').first()?.json ?? {};
const updated = $('Log Outbound Email').first()?.json ?? {};
let redirectTo = item.return_url || (item.n8n_base_url + '/webhook/case-tracking?view=dashboard');
if (updated.case_id) redirectTo = item.n8n_base_url + '/webhook/case-tracking?view=case&id=' + encodeURIComponent(updated.case_id);
redirectTo += (redirectTo.includes('?') ? '&' : '?') + 'message=' + encodeURIComponent('Email sent');
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const modeLabel = item.delivery_mode === 'production' ? 'Production' : 'Test';
const recipientSummary = item.delivery_mode === 'production' ? item.actual_recipient : item.actual_recipient + ' (intended recipient: ' + item.intended_recipient + ')';
const html = '<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=' + escapeHtml(redirectTo) + '"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Email sent</title></head><body><p>Email sent in ' + escapeHtml(modeLabel) + ' mode.</p><p>Recipient: ' + escapeHtml(recipientSummary) + '</p><p><a href="' + escapeHtml(redirectTo) + '">Back to case</a></p></body></html>';
return [{ json: { html } }];
